{
  "summary": "天猫618大促选品需满足销量、好评率和库存三项基本条件。",
  "checklist": [
    {
      "condition": "近30天销量≥100件",
      "priority": "high",
      "detail": "商品近30天累计销量须≥100件"
    },
    {
      "condition": "好评率≥95%",
      "priority": "high",
      "detail": "商品好评率须≥95%"
    },
    {
      "condition": "库存≥500件",
      "priority": "high",
      "detail": "商品当前库存须≥500件"
    }
  ],
  "risks": [
    {
      "description": "销量或库存数据可能因时间窗口波动，需在活动前确认实时数据达标",
      "severity": "high"
    },
    {
      "description": "好评率计算口径（如仅含确认收货订单）不明确，可能导致数据差异",
      "severity": "medium"
    }
  ],
  "needs_clarification": [
    "近30天销量的统计截止时间点？",
    "好评率计算是否排除默认好评或已删除评价？",
    "库存是否指活动期间可售库存，是否包含预售或占用库存？"
  ]
}

{
  "summary": "从符合天猫618大促基础条件的商品中，筛选出满足销量、评价、库存、价格及品类限制，且未参与品牌日活动的推荐商品。",
  "checklist": [
    {
      "condition": "商品近30天销量≥100件",
      "priority": "high",
      "detail": "销量≥100"
    },
    {
      "condition": "商品好评率≥95%",
      "priority": "high",
      "detail": "好评率≥95%"
    },
    {
      "condition": "商品库存≥500件",
      "priority": "high",
      "detail": "库存≥500"
    },
    {
      "condition": "活动价不得高于近30天最低价",
      "priority": "high",
      "detail": "活动价 ≤ 近30天最低价"
    },
    {
      "condition": "折扣力度≥7折",
      "priority": "high",
      "detail": "折扣力度≥7折（即活动价/标价 ≤ 0.7）"
    },
    {
      "condition": "黄金类商品单店最多5个SKU",
      "priority": "high",
      "detail": "黄金类SKU数量≤5"
    },
    {
      "condition": "钻石类商品单店最多10个SKU",
      "priority": "high",
      "detail": "钻石类SKU数量≤10"
    },
    {
      "condition": "已参加'品牌日'活动的商品不可重复报名",
      "priority": "high",
      "detail": "该商品未报名品牌日活动"
    }
  ],
  "risks": [
    {
      "description": "若推荐商品包含黄金或钻石品类，SKU数量可能超出限制（黄金≤5、钻石≤10），导致部分商品无法参与活动。",
      "severity": "high"
    },
    {
      "description": "商品可能已参加品牌日活动但未被标注，导致重复报名失败。",
      "severity": "medium"
    }
  ],
  "needs_clarification": [
    "请提供候选商品的详细列表，包括近30天销量、好评率、库存数量、价格信息以及品类（是否黄金/钻石）。",
    "请确认候选商品是否已经报名品牌日活动。",
    "若候选商品包含黄金或钻石品类，请说明当前各店已有该类商品报名的SKU数量。",
    "请提供商品近30天最低价，以便核算活动价是否符合要求。"
  ]
}
